#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding gynecology-assessment (16 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    ethnicity:string! \
    primary_language:string! \
    interpreter_required:string! \
    marital_status:string! \
    occupation:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    emergency_contact_relationship:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    primary_complaint:text! \
    symptom_duration:string! \
    symptom_onset:string! \
    symptom_severity:int \
    symptom_pattern:string! \
    aggravating_factors:text! \
    relieving_factors:text! \
    impact_on_daily_life:string! \
    previous_treatment_for_complaint:string! \
    previous_treatment_details:text! \
    --htmx

cargo loco generate scaffold assessment_menstrual_history \
    assessment:references \
    menarche_age:int \
    menstrual_status:string! \
    cycle_length_days:int \
    period_duration_days:int \
    flow_volume:string! \
    menorrhagia:string! \
    dysmenorrhoea:string! \
    dysmenorrhoea_severity:int \
    intermenstrual_bleeding:string! \
    postcoital_bleeding:string! \
    post_menopausal_bleeding:string! \
    last_menstrual_period_date:date \
    menopause_age:int \
    menstrual_notes:text! \
    --htmx

cargo loco generate scaffold assessment_gynecological_symptoms \
    assessment:references \
    pelvic_pain:string! \
    pelvic_pain_severity:int \
    pelvic_pain_location:string! \
    dyspareunia:string! \
    dyspareunia_type:string! \
    vaginal_discharge:string! \
    discharge_characteristics:string! \
    vulval_symptoms:string! \
    vulval_symptom_details:text! \
    urinary_symptoms:string! \
    urinary_symptom_type:string! \
    pelvic_organ_prolapse_symptoms:string! \
    prolapse_details:text! \
    bloating:string! \
    bowel_symptoms:string! \
    bowel_symptom_details:text! \
    symptom_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cervical_screening \
    assessment:references \
    last_smear_date:date \
    smear_result:string! \
    hpv_status:string! \
    hpv_vaccination:string! \
    colposcopy_history:string! \
    colposcopy_details:text! \
    cervical_treatment_history:string! \
    cervical_treatment_type:string! \
    cervical_treatment_details:text! \
    screening_up_to_date:string! \
    screening_notes:text! \
    --htmx

cargo loco generate scaffold assessment_obstetric_history \
    assessment:references \
    gravida:int \
    para:int \
    number_of_miscarriages:int \
    number_of_terminations:int \
    number_of_ectopics:int \
    number_of_stillbirths:int \
    currently_pregnant:string! \
    gestational_age_weeks:int \
    delivery_complications:string! \
    delivery_complication_details:text! \
    caesarean_section_history:string! \
    number_of_caesareans:int \
    gestational_diabetes:string! \
    pre_eclampsia:string! \
    obstetric_notes:text! \
    --htmx

cargo loco generate scaffold assessment_sexual_health \
    assessment:references \
    sexually_active:string! \
    contraception_use:string! \
    contraception_method:string! \
    contraception_details:text! \
    sti_history:string! \
    sti_details:text! \
    last_sti_screen_date:date \
    sti_screen_result:string! \
    fertility_concerns:string! \
    fertility_concern_details:text! \
    sexual_dysfunction:string! \
    sexual_dysfunction_details:text! \
    domestic_abuse_screen:string! \
    sexual_health_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    has_endometriosis:string! \
    endometriosis_details:text! \
    has_fibroids:string! \
    fibroid_details:text! \
    has_pcos:string! \
    has_ovarian_cysts:string! \
    ovarian_cyst_details:text! \
    previous_gynaecological_surgery:string! \
    gynaecological_surgery_details:text! \
    has_thyroid_disorder:string! \
    thyroid_details:text! \
    has_clotting_disorder:string! \
    clotting_disorder_details:text! \
    has_autoimmune_condition:string! \
    autoimmune_details:text! \
    has_mental_health_condition:string! \
    mental_health_details:text! \
    other_medical_conditions:text! \
    previous_surgeries:text! \
    allergies:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_regular_medications:string! \
    takes_over_the_counter:string! \
    takes_herbal_supplements:string! \
    herbal_supplement_details:text! \
    hormone_therapy:string! \
    hormone_therapy_details:text! \
    medication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    indication:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_family_history \
    assessment:references \
    family_history_breast_cancer:string! \
    breast_cancer_details:text! \
    family_history_ovarian_cancer:string! \
    ovarian_cancer_details:text! \
    family_history_endometrial_cancer:string! \
    endometrial_cancer_details:text! \
    family_history_cervical_cancer:string! \
    family_history_endometriosis:string! \
    family_history_fibroids:string! \
    family_history_pcos:string! \
    family_history_early_menopause:string! \
    family_history_osteoporosis:string! \
    family_history_thromboembolism:string! \
    other_family_history:text! \
    family_history_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    severity_level:string! \
    total_symptom_score:int! \
    menstrual_domain_score:int! \
    pelvic_symptom_score:int! \
    urogenital_symptom_score:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
